package events

import "github.com/google/uuid"

// Entity interfaces for extracting common fields from Ent-generated entities.
// These interfaces match the getter methods generated by Ent for mixin fields.

// IDer can provide its unique identifier.
// All Ent entities with a UUID primary key implement this interface.
type IDer interface {
	GetID() uuid.UUID
}

// TenantIDer can provide its tenant identifier.
// Entities using TenantMixin implement this interface.
type TenantIDer interface {
	GetTenantID() uuid.UUID
}

// DataTypeSlugger can provide its data type slug.
// Entities using DataMixin implement this interface.
type DataTypeSlugger interface {
	GetDataTypeSlug() string
}

// MutationEntity combines all interfaces needed for mutation event handling.
// This is a convenience interface for entities that support full event middleware.
type MutationEntity interface {
	IDer
	TenantIDer
}
